class Solution:
    def deckRevealedIncreasing(self, deck):
        from collections import deque
        n = len(deck)
        deck = sorted(deck)
        idx = deque(range(n))
        res = [0] * n
        for card in deck:
            pos = idx.popleft()
            res[pos] = card
            if idx:
                idx.append(idx.popleft())
        return res

