var deckRevealedIncreasing = function(deck) {
    const n = deck.length;
    deck.sort((a, b) => a - b);
    const idx = Array.from({length: n}, (_, i) => i);
    const res = new Array(n).fill(0);
    let qi = 0;
    const queue = [...idx];
    let head = 0;
    for (const card of deck) {
